eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   hi: () => (/* binding */ hi)\n/* harmony export */ });\n// Curated English -> Hindi dictionary for the whole site.\n// Keys are the exact (trimmed) English text as it appears in a DOM text node.\n// Anything not listed here safely stays in English.\nconst hi = {\n    // ---- Navbar ----\n    \"Home\": \"होम\",\n    \"About Us\": \"हमारे बारे में\",\n    \"Events\": \"कार्यक्रम\",\n    \"SDG\": \"एसडीजी\",\n    \"Partners\": \"साझेदार\",\n    \"Contact\": \"संपर्क\",\n    \"Work With Us\": \"हमारे साथ काम करें\",\n    \"work With Us\": \"हमारे साथ काम करें\",\n    \"Get in Touch\": \"संपर्क करें\",\n    // ---- Footer ----\n    \"Quick Links\": \"त्वरित लिंक\",\n    \"Languages\": \"भाषाएँ\",\n    \"English\": \"अंग्रेज़ी\",\n    \"Hindi\": \"हिंदी\",\n    \"Uniting students, schools, NGOs and companies to build a better, sustainable and inclusive world.\": \"एक बेहतर, टिकाऊ और समावेशी दुनिया बनाने के लिए छात्रों, स्कूलों, एनजीओ और कंपनियों को एकजुट करना।\",\n    // ---- Home hero ----\n    \"Global Education Impact Platform\": \"वैश्विक शिक्षा प्रभाव मंच\",\n    \"Students, Companies and NGOs for\": \"छात्र, कंपनियाँ और एनजीओ —\",\n    \"SDG Impact\": \"एसडीजी प्रभाव\",\n    \"Connecting schools, NGOs, companies and communities to improve education through SDG 4.\": \"एसडीजी 4 के माध्यम से शिक्षा को बेहतर बनाने हेतु स्कूलों, एनजीओ, कंपनियों और समुदायों को जोड़ना।\",\n    // ---- About hero ----\n    \"Purpose-driven partnerships for a\": \"उद्देश्य-संचालित साझेदारियाँ एक\",\n    \"better tomorrow\": \"बेहतर कल के लिए\",\n    \"We bring together schools, NGOs, companies and communities to deliver transparent, measurable impact aligned with the UN Sustainable Development Goals.\": \"हम स्कूलों, एनजीओ, कंपनियों और समुदायों को एक साथ लाते हैं ताकि संयुक्त राष्ट्र सतत विकास लक्ष्यों के अनुरूप पारदर्शी, मापने योग्य प्रभाव प्रदान किया जा सके।\",\n    // ---- Vision & Mission ----\n    \"Vision & Mission\": \"दृष्टि और लक्ष्य\",\n    \"Building a Future Where Every Child Has Equal Access to Quality Education\": \"एक ऐसा भविष्य बनाना जहाँ हर बच्चे को गुणवत्तापूर्ण शिक्षा तक समान पहुँच हो\",\n    \"Our Vision\": \"हमारी दृष्टि\",\n    \"Our Mission\": \"हमारा लक्ष्य\",\n    \"Empowering Every Learner to Build a Better Tomorrow\": \"हर शिक्षार्थी को बेहतर कल बनाने के लिए सशक्त बनाना\",\n    \"We envision a future where every child, regardless of geography, income, or background, has equal access to quality education, technology, and opportunities that unlock their full potential.\": \"हम एक ऐसे भविष्य की कल्पना करते हैं जहाँ हर बच्चे को, चाहे उसका भूगोल, आय या पृष्ठभूमि कुछ भी हो, गुणवत्तापूर्ण शिक्षा, तकनीक और अवसरों तक समान पहुँच हो जो उसकी पूरी क्षमता को उजागर करें।\",\n    \"StepUp for SDG aims to create inclusive schools, empowered educators, and connected communities that inspire lifelong learning and sustainable development.\": \"स्टेपअप फॉर एसडीजी का लक्ष्य समावेशी स्कूल, सशक्त शिक्षक और जुड़े हुए समुदाय बनाना है जो आजीवन सीखने और सतत विकास को प्रेरित करें।\",\n    \"Education is the foundation for lasting change.\": \"शिक्षा स्थायी बदलाव की नींव है।\",\n    \"Transforming Partnerships into Measurable Educational Impact\": \"साझेदारियों को मापने योग्य शैक्षिक प्रभाव में बदलना\",\n    \"Our mission is to connect schools, NGOs, companies, volunteers, and communities through one collaborative platform that enables transparent educational initiatives, innovation, and measurable social impact.\": \"हमारा लक्ष्य स्कूलों, एनजीओ, कंपनियों, स्वयंसेवकों और समुदायों को एक सहयोगी मंच के माध्यम से जोड़ना है जो पारदर्शी शैक्षिक पहल, नवाचार और मापने योग्य सामाजिक प्रभाव को सक्षम बनाता है।\",\n    \"Every contribution helps children gain knowledge, confidence, and opportunities for a brighter future.\": \"हर योगदान बच्चों को ज्ञान, आत्मविश्वास और उज्जवल भविष्य के अवसर पाने में मदद करता है।\",\n    \"Together we create opportunities that transform lives.\": \"साथ मिलकर हम ऐसे अवसर बनाते हैं जो जीवन बदल देते हैं।\",\n    \"Explore Our Vision\": \"हमारी दृष्टि देखें\",\n    // ---- Navbar extra ----\n    \"Funds\": \"फंड्स\",\n    // ---- Home page ----\n    \"Three ways to make impact together\": \"साथ मिलकर प्रभाव बनाने के तीन तरीके\",\n    \"Companies\": \"कंपनियाँ\",\n    \"Channel CSR funding into transparent, measurable education programs and track impact in real time.\": \"पारदर्शी, मापने योग्य शिक्षा कार्यक्रमों में सीएसआर फंडिंग लगाएं और रियल टाइम में प्रभाव ट्रैक करें।\",\n    \"Explore Partnership\": \"साझेदारी देखें\",\n    \"Join our network to access resources, infrastructure support and quality learning programs.\": \"संसाधनों, बुनियादी ढाँचे और गुणवत्तापूर्ण शिक्षा कार्यक्रमों तक पहुँचने के लिए हमारे नेटवर्क में शामिल हों।\",\n    \"Join as School\": \"स्कूल के रूप में जुड़ें\",\n    \"NGOs\": \"एनजीओ\",\n    \"Collaborate on the ground to uplift communities and deliver lasting, sustainable social change.\": \"समुदायों को ऊपर उठाने और स्थायी सामाजिक बदलाव लाने के लिए जमीनी स्तर पर सहयोग करें।\",\n    \"Collaborate Now\": \"अभी सहयोग करें\",\n    // ---- Live Impact Map ----\n    \"Live Impact Count\": \"लाइव प्रभाव गणना\",\n    \"Impact across the world\": \"दुनिया भर में प्रभाव\",\n    \"Track education impact across schools, NGOs and partner regions.\": \"स्कूलों, एनजीओ और साझेदार क्षेत्रों में शिक्षा प्रभाव ट्रैक करें।\",\n    \"Search country…\": \"देश खोजें…\",\n    \"High Impact\": \"उच्च प्रभाव\",\n    \"Medium Impact\": \"मध्यम प्रभाव\",\n    \"Low Impact\": \"कम प्रभाव\",\n    \"No Data\": \"कोई डेटा नहीं\",\n    \"Active Projects\": \"सक्रिय परियोजनाएँ\",\n    \"NGO Partners\": \"एनजीओ साझेदार\",\n    \"Students Enrolled\": \"नामांकित छात्र\",\n    \"Volunteer Hours\": \"स्वयंसेवक घंटे\",\n    \"No impact data available yet for this country.\": \"इस देश के लिए अभी कोई प्रभाव डेटा उपलब्ध नहीं है।\",\n    // ---- Vision Banner ----\n    \"United for Tomorrow\": \"कल के लिए एकजुट\",\n    \"UNITE 2030 Vision\": \"यूनाइट 2030 विज़न\",\n    \"Building a future through collaboration, education, innovation and community-driven impact.\": \"सहयोग, शिक्षा, नवाचार और समुदाय-संचालित प्रभाव के माध्यम से एक भविष्य बनाना।\",\n    \"Become a Partner\": \"साझेदार बनें\",\n    \"Contact Us\": \"हमसे संपर्क करें\",\n    // ---- Events page ----\n    \"SDG EVENTS & IMPACT SESSIONS\": \"एसडीजी कार्यक्रम और प्रभाव सत्र\",\n    \"Join education drives, school innovation workshops, NGO collaborations, CSR partner meets, and youth-led SDG action events that create measurable impact.\": \"शिक्षा अभियानों, स्कूल नवाचार कार्यशालाओं, एनजीओ सहयोगों, सीएसआर साझेदार बैठकों और युवा-नेतृत्व वाले एसडीजी कार्यक्रमों में शामिल हों।\",\n    \"Explore Events\": \"कार्यक्रम देखें\",\n    \"Host an Event\": \"कार्यक्रम होस्ट करें\",\n    \"Upcoming\": \"आगामी\",\n    \"Browse SDG\": \"एसडीजी देखें\",\n    \"education events\": \"शिक्षा कार्यक्रम\",\n    \"Filter by the kind of impact you want to create — from school drives to youth innovation challenges.\": \"उस प्रकार के प्रभाव के अनुसार फ़िल्टर करें जो आप बनाना चाहते हैं — स्कूल अभियानों से लेकर युवा नवाचार चुनौतियों तक।\",\n    \"Load More Events\": \"और कार्यक्रम लोड करें\",\n    \"All Events\": \"सभी कार्यक्रम\",\n    \"School Drives\": \"स्कूल अभियान\",\n    \"Workshops\": \"कार्यशालाएँ\",\n    \"CSR Meets\": \"सीएसआर बैठकें\",\n    \"NGO Collaboration\": \"एनजीओ सहयोग\",\n    \"Youth Challenges\": \"युवा चुनौतियाँ\",\n    \"Roadmap\": \"रोडमैप\",\n    \"Event\": \"कार्यक्रम\",\n    \"timeline\": \"समयरेखा\",\n    \"Moments\": \"पल\",\n    \"From our\": \"हमारी\",\n    \"impact gallery\": \"प्रभाव गैलरी\",\n    \"Snapshots from classrooms, workshops, and community sessions across our partner network.\": \"हमारे साझेदार नेटवर्क में कक्षाओं, कार्यशालाओं और सामुदायिक सत्रों की झलकियाँ।\",\n    \"Get Involved\": \"शामिल हों\",\n    \"Create impact\": \"प्रभाव बनाएं\",\n    \"your way\": \"अपने तरीके से\",\n    \"Host an SDG Event\": \"एसडीजी कार्यक्रम होस्ट करें\",\n    \"Bring an education drive or workshop to your school or community.\": \"अपने स्कूल या समुदाय में एक शिक्षा अभियान या कार्यशाला लाएं।\",\n    \"Start hosting\": \"होस्टिंग शुरू करें\",\n    \"Volunteer With Us\": \"हमारे साथ स्वयंसेवा करें\",\n    \"Mentor students and support learning sessions on the ground.\": \"छात्रों को मार्गदर्शन दें और जमीनी स्तर पर शिक्षण सत्रों का समर्थन करें।\",\n    \"Join as volunteer\": \"स्वयंसेवक के रूप में जुड़ें\",\n    \"Partner as NGO\": \"एनजीओ के रूप में साझेदारी करें\",\n    \"Collaborate, share resources, and scale rural school support.\": \"सहयोग करें, संसाधन साझा करें और ग्रामीण स्कूल समर्थन बढ़ाएं।\",\n    \"Become a partner\": \"साझेदार बनें\",\n    \"Sponsor Education Impact\": \"शिक्षा प्रभाव को प्रायोजित करें\",\n    \"Fund transparent, measurable CSR education programs.\": \"पारदर्शी, मापने योग्य सीएसआर शिक्षा कार्यक्रमों को फंड करें।\",\n    \"Sponsor a program\": \"एक कार्यक्रम प्रायोजित करें\",\n    // ---- Partners page ----\n    \"Join the Movement\": \"आंदोलन में शामिल हों\",\n    \"Partner With\": \"साझेदारी करें\",\n    \"Whether you bring funding, classrooms, expertise or time — there's a place for you in the mission to transform education.\": \"चाहे आप फंडिंग, कक्षाएं, विशेषज्ञता या समय लाएं — शिक्षा को बदलने के मिशन में आपके लिए जगह है।\",\n    \"Corporate CSR Partners\": \"कॉर्पोरेट सीएसआर साझेदार\",\n    \"Direct your CSR investments into transparent, measurable, outcome-driven education programs.\": \"अपने सीएसआर निवेश को पारदर्शी, मापने योग्य, परिणाम-उन्मुख शिक्षा कार्यक्रमों में लगाएं।\",\n    \"Get access to digital tools, infrastructure support and quality learning programs.\": \"डिजिटल टूल्स, बुनियादी ढाँचे के समर्थन और गुणवत्तापूर्ण शिक्षा कार्यक्रमों तक पहुँच प्राप्त करें।\",\n    \"Co-create programs on the ground and amplify your social impact with scalable systems.\": \"जमीनी स्तर पर कार्यक्रम सह-निर्मित करें और स्केलेबल सिस्टम के साथ अपना सामाजिक प्रभाव बढ़ाएं।\",\n    \"Volunteers\": \"स्वयंसेवक\",\n    \"Lend your skills, time and energy to build a better future for students worldwide.\": \"दुनिया भर के छात्रों के लिए बेहतर भविष्य बनाने के लिए अपने कौशल, समय और ऊर्जा का योगदान दें।\",\n    \"Get Started\": \"शुरू करें\",\n    // ---- 5P Model ----\n    \"People\": \"लोग\",\n    \"Planet\": \"ग्रह\",\n    \"Prosperity\": \"समृद्धि\",\n    \"Peace\": \"शांति\",\n    \"Partnership\": \"साझेदारी\",\n    \"click to explore\": \"जानने के लिए क्लिक करें\",\n    // ---- Team ----\n    \"Click to learn more\": \"अधिक जानने के लिए क्लिक करें\",\n    \"Founder & Director\": \"संस्थापक और निदेशक\",\n    \"Head of Partnerships\": \"साझेदारी प्रमुख\",\n    \"Programs Lead\": \"कार्यक्रम प्रमुख\",\n    \"Impact & Research\": \"प्रभाव और अनुसंधान\",\n    // ---- About page ----\n    \"Whether you're a school, NGO, company or volunteer, there's a place for you in building a future where every child has access to quality education.\": \"चाहे आप एक स्कूल, एनजीओ, कंपनी या स्वयंसेवक हों, हर बच्चे को गुणवत्तापूर्ण शिक्षा तक पहुँच वाला भविष्य बनाने में आपके लिए जगह है।\",\n    \"Future Learners\": \"भविष्य के शिक्षार्थी\",\n    \"Schools\": \"स्कूल\",\n    \"Regions\": \"क्षेत्र\",\n    \"Partners \": \"साझेदार\",\n    \"Projects\": \"परियोजनाएँ\",\n    \"Lives Impacted\": \"प्रभावित जीवन\",\n    // ---- Our Story ----\n    \"Who We Are\": \"हम कौन हैं\",\n    \"Our Story\": \"हमारी कहानी\",\n    \"StepUp for SDG began with a simple conviction: that quality education is the most powerful lever for lasting change. What started as a handful of volunteers supporting local schools has grown into a collaborative platform uniting students, educators, NGOs and companies around a shared mission.\": \"स्टेपअप फॉर एसडीजी की शुरुआत एक सरल विश्वास से हुई: कि गुणवत्तापूर्ण शिक्षा स्थायी बदलाव का सबसे शक्तिशाली माध्यम है। जो कुछ स्वयंसेवकों द्वारा स्थानीय स्कूलों के समर्थन के रूप में शुरू हुआ, वह अब एक सहयोगी मंच बन गया है जो छात्रों, शिक्षकों, एनजीओ और कंपनियों को एक साझा मिशन के इर्द-गिर्द एकजुट करता है।\",\n    \"Today we connect partners across regions to fund, design and deliver transparent educational initiatives — turning intention into measurable impact for the children who need it most.\": \"आज हम विभिन्न क्षेत्रों के साझेदारों को जोड़ते हैं ताकि पारदर्शी शैक्षिक पहल को वित्तपोषित, डिज़ाइन और कार्यान्वित किया जा सके — इरादे को उन बच्चों के लिए मापने योग्य प्रभाव में बदलते हुए जिन्हें इसकी सबसे अधिक आवश्यकता है।\",\n    \"We believe progress should be visible. Every project we support is tracked, reported, and built to last, so every contribution becomes a real opportunity for a learner.\": \"हम मानते हैं कि प्रगति दिखाई देनी चाहिए। हम जिस भी परियोजना का समर्थन करते हैं उसे ट्रैक किया जाता है, रिपोर्ट किया जाता है और टिकाऊ बनाया जाता है, ताकि हर योगदान किसी शिक्षार्थी के लिए एक वास्तविक अवसर बन सके।\",\n    // ---- Our Impact ----\n    \"Our Impact\": \"हमारा प्रभाव\",\n    \"Real, measurable change — driven by partnerships that put learners first and build educational ecosystems designed to last.\": \"वास्तविक, मापने योग्य बदलाव — ऐसी साझेदारियों से प्रेरित जो शिक्षार्थियों को प्राथमिकता देती हैं और टिकाऊ शैक्षिक तंत्र बनाती हैं।\",\n    \"Education Access\": \"शिक्षा तक पहुँच\",\n    \"Supporting quality education for underserved communities.\": \"वंचित समुदायों के लिए गुणवत्तापूर्ण शिक्षा का समर्थन।\",\n    \"School Development\": \"स्कूल विकास\",\n    \"Helping schools with infrastructure, digital learning, and resources.\": \"स्कूलों को बुनियादी ढाँचे, डिजिटल शिक्षा और संसाधनों में मदद करना।\",\n    \"Partnerships\": \"साझेदारियाँ\",\n    \"Connecting NGOs, schools, volunteers, and companies to create measurable impact.\": \"मापने योग्य प्रभाव बनाने के लिए एनजीओ, स्कूलों, स्वयंसेवकों और कंपनियों को जोड़ना।\",\n    \"Sustainable Communities\": \"टिकाऊ समुदाय\",\n    \"Building long-term educational ecosystems that support the UN Sustainable Development Goals.\": \"दीर्घकालिक शैक्षिक तंत्र बनाना जो संयुक्त राष्ट्र सतत विकास लक्ष्यों का समर्थन करते हैं।\",\n    \"Students Impacted\": \"प्रभावित छात्र\",\n    \"Schools Supported\": \"समर्थित स्कूल\",\n    \"Partner Organizations\": \"साझेदार संगठन\",\n    \"Projects Completed\": \"पूर्ण परियोजनाएँ\",\n    // ---- 5P Model ----\n    \"5P Model\": \"5पी मॉडल\",\n    \"Five pillars of sustainable impact\": \"सतत प्रभाव के पाँच स्तंभ\",\n    // ---- Team ----\n    \"Our Team\": \"हमारी टीम\",\n    // ---- Join CTA ----\n    \"Join Our\": \"हमारे साथ जुड़ें\",\n    \"Mission\": \"मिशन\",\n    // ---- Connecting schools line (home page exact text) ----\n    \"Connecting schools, NGOs, companies and communities to improve education through SDG .\": \"एसडीजी के माध्यम से शिक्षा को बेहतर बनाने हेतु स्कूलों, एनजीओ, कंपनियों और समुदायों को जोड़ना।\",\n    // ---- Team Card Bios ----\n    \"Aarav founded StepUp for SDG with a vision to bridge the gap between corporate resources and grassroots education needs. With 12 years in social impact, he has led programmes touching 200,000+ students.\": \"आरव ने कॉर्पोरेट संसाधनों और जमीनी शिक्षा ज़रूरतों के बीच की खाई पाटने की दृष्टि से स्टेपअप फॉर एसडीजी की स्थापना की। 12 साल के सामाजिक प्रभाव के अनुभव के साथ, उन्होंने 2,00,000+ छात्रों तक पहुँचने वाले कार्यक्रमों का नेतृत्व किया है।\",\n    \"Priya builds and manages relationships with corporate partners and NGOs. She has structured over 40 CSR partnerships and is a recognised voice in impact investment circles.\": \"प्रिया कॉर्पोरेट साझेदारों और एनजीओ से संबंध बनाती और प्रबंधित करती हैं। उन्होंने 40 से अधिक सीएसआर साझेदारियाँ तैयार की हैं और प्रभाव निवेश क्षेत्र में एक मान्यताप्राप्त आवाज़ हैं।\",\n    \"Rahul oversees programme design and field delivery across 18 regions. A former teacher himself, he ensures every initiative stays rooted in real classroom needs.\": \"राहुल 18 क्षेत्रों में कार्यक्रम डिज़ाइन और जमीनी डिलीवरी की निगरानी करते हैं। खुद पूर्व शिक्षक होने के नाते, वे सुनिश्चित करते हैं कि हर पहल वास्तविक कक्षा की ज़रूरतों से जुड़ी रहे।\",\n    \"Sara leads our impact measurement framework, turning field data into compelling evidence. She holds an MSc in Development Economics from LSE.\": \"सारा हमारे प्रभाव माप ढांचे की अगुवाई करती हैं, जमीनी डेटा को ठोस साक्ष्य में बदलती हैं। उनके पास एलएसई से विकास अर्थशास्त्र में एमएससी है।\",\n    // ---- Event Card ----\n    \"View Details & Register\": \"विवरण देखें और पंजीकरण करें\",\n    \"No events in this category yet — check back soon.\": \"इस श्रेणी में अभी कोई कार्यक्रम नहीं — जल्द वापस देखें।\",\n    // ---- Featured Event ----\n    \"★ Featured Event\": \"★ विशेष कार्यक्रम\",\n    \"Starts in 51 days\": \"51 दिनों में शुरू होगा\",\n    \"Youth Challenges · SDG 4\": \"युवा चुनौतियाँ · एसडीजी 4\",\n    \"12+ student innovators & mentors\": \"12+ छात्र नवोन्मेषक और मार्गदर्शक\",\n    \"In partnership with\": \"साझेदारी में\",\n    \"Register Now\": \"अभी पंजीकरण करें\",\n    // ---- Event descriptions ----\n    \"Volunteers and partner schools collaborate to improve classrooms, learning corners, and student engagement.\": \"स्वयंसेवक और साझेदार स्कूल कक्षाओं, सीखने के कोनों और छात्र जुड़ाव को बेहतर बनाने के लिए सहयोग करते हैं।\",\n    \"Companies, NGOs, and educators discuss transparent CSR funding for measurable education impact.\": \"कंपनियाँ, एनजीओ और शिक्षक मापने योग्य शिक्षा प्रभाव के लिए पारदर्शी सीएसआर फंडिंग पर चर्चा करते हैं।\",\n    \"Training session for students on digital literacy, AI tools, and safe technology usage.\": \"डिजिटल साक्षरता, एआई टूल्स और सुरक्षित तकनीक उपयोग पर छात्रों के लिए प्रशिक्षण सत्र।\",\n    \"NGOs working in education connect to share resources, volunteers, and rural school support plans.\": \"शिक्षा में काम करने वाले एनजीओ संसाधन, स्वयंसेवक और ग्रामीण स्कूल समर्थन योजनाएं साझा करने के लिए जुड़ते हैं।\",\n    \"Students present innovative ideas for SDG 4 Quality Education and community development.\": \"छात्र एसडीजी 4 गुणवत्तापूर्ण शिक्षा और सामुदायिक विकास के लिए अभिनव विचार प्रस्तुत करते हैं।\",\n    \"Workshop for teachers on interactive learning methods, inclusive classrooms, and student motivation.\": \"इंटरैक्टिव शिक्षण विधियों, समावेशी कक्षाओं और छात्र प्रेरणा पर शिक्षकों के लिए कार्यशाला।\",\n    // ---- Event titles ----\n    \"School Transformation Drive\": \"स्कूल परिवर्तन अभियान\",\n    \"CSR Education Partnership Meet\": \"सीएसआर शिक्षा साझेदारी बैठक\",\n    \"Digital Learning Workshop\": \"डिजिटल शिक्षा कार्यशाला\",\n    \"NGO Collaboration Summit\": \"एनजीओ सहयोग शिखर सम्मेलन\",\n    \"SDG Youth Innovation Challenge\": \"एसडीजी युवा नवाचार चुनौती\",\n    \"Teacher Empowerment Session\": \"शिक्षक सशक्तिकरण सत्र\",\n    // ---- Gallery labels ----\n    \"Classroom learning\": \"कक्षा में सीखना\",\n    \"Young learners\": \"युवा शिक्षार्थी\",\n    \"Workshop session\": \"कार्यशाला सत्र\",\n    \"NGO collaboration\": \"एनजीओ सहयोग\",\n    \"CSR partner meet\": \"सीएसआर साझेदार बैठक\",\n    \"Digital learning lab\": \"डिजिटल शिक्षा प्रयोगशाला\"\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./app/i18n/dictionary.ts\n");

